from pathlib import Path
import sys
import shutil

TARGET = Path(sys.argv[1]) if len(sys.argv) > 1 else Path("App.jsx")

if not TARGET.exists():
    print(f"❌ Fichier introuvable : {TARGET}")
    print("➡️ Mets ce patch dans le dossier src puis lance : python patch_fin_qcm2_game_v2.py App.jsx")
    raise SystemExit(1)

text = TARGET.read_text(encoding="utf-8")

backup = TARGET.with_name(TARGET.name + ".backup_fin_qcm2_game_v2")
shutil.copy2(TARGET, backup)

start = text.find("function RecommandationsQcm2Screen")
if start == -1:
    print("❌ Impossible de trouver function RecommandationsQcm2Screen")
    raise SystemExit(1)

end = text.find("\n/* ══ COMPOSANT INGRÉDIENTS", start)
if end == -1:
    print("❌ Impossible de trouver la fin du composant RecommandationsQcm2Screen")
    raise SystemExit(1)

new_component = r'function RecommandationsQcm2Screen({ answers, onBack, onVoirRecettes, playerName, avatarChoice }) {\n  const [etape, setEtape] = useState(0);\n\n  const cuisine = answers?.[" En cuisine"] || "";\n  const pratiques = answers?.[" Pratiques alimentaires"] || "";\n  const nbRepas = answers?.[" Nombre de repas"] || "";\n\n  const avatarSrc = avatarChoice === "garcon" ? "/garcon.png" : avatarChoice === "fille" ? "/fille.png" : "/avatar.png";\n\n  const profilRecos = [];\n  if (pratiques === "Je mange sans viande") {\n    profilRecos.push({\n      key:"vegetarien",\n      label:"Profil végétarien",\n      icon:"/legumesec.png",\n      couleur:"#558B2F",\n      bg:"#F1F8E9",\n      texte:"Ton profil indique que tu dois renforcer les protéines végétales : lentilles, pois chiches, haricots, œufs ou produits laitiers selon tes habitudes.",\n      conseils:["Associe légumineuses + féculents complets","Ajoute des fruits et légumes à chaque repas","Prévois une source de protéines à chaque menu"],\n      profil:"vegetarien"\n    });\n  }\n  if (cuisine === "Je n\'ai pas le temps") {\n    profilRecos.push({\n      key:"rapide",\n      label:"Profil pressé",\n      icon:"/marmitte.png",\n      couleur:"#E65100",\n      bg:"#FFF3E0",\n      texte:"Tu as besoin de recettes simples, rapides et équilibrées. Max te conseille des repas en moins de 30 minutes.",\n      conseils:["Prépare des bases à l\'avance","Garde des conserves utiles : thon, sardines, lentilles","Utilise légumes surgelés + féculents rapides"],\n      profil:"rapide"\n    });\n  }\n  if (pratiques === "Je mange sans porc") {\n    profilRecos.push({\n      key:"sans_porc",\n      label:"Profil sans porc",\n      icon:"/poisson.png",\n      couleur:"#0277BD",\n      bg:"#E1F5FE",\n      texte:"Tes recettes doivent éviter le porc et la charcuterie. On garde des alternatives : poisson, volaille, œufs et légumineuses.",\n      conseils:["Remplace les lardons par du thon, du poulet ou des pois chiches","Vérifie les ingrédients des plats préparés","Mise sur les épices pour donner du goût"],\n      profil:"sans_porc"\n    });\n  }\n  if (profilRecos.length === 0) {\n    profilRecos.push({\n      key:"equilibre",\n      label:"Profil équilibre",\n      icon:"/assiette1.png",\n      couleur:"#00BFA5",\n      bg:"#E0F7F5",\n      texte:"Ton profil est assez polyvalent. Ta mission : construire des repas équilibrés, variés et proches des repères PNNS.",\n      conseils:["Augmente les fruits et légumes","Garde une source de protéines","Privilégie l\'eau et limite les boissons sucrées"],\n      profil:"mediterraneen"\n    });\n  }\n\n  const profilPrincipal = profilRecos[0];\n  const badgeRepas = nbRepas ? nbRepas : "Rythme à préciser";\n  const missionScore = Math.min(100, 55 + profilRecos.length * 15 + (cuisine ? 10 : 0) + (pratiques ? 10 : 0));\n\n  const goNext = () => {\n    playSound("next");\n    setEtape(v => Math.min(v + 1, 2));\n  };\n\n  const GameButton = ({ children, onClick, variant }) => (\n    <button\n      onClick={() => { playSound("click"); onClick(); }}\n      style={{\n        background: variant === "green" ? "#9ACD32" : variant === "blue" ? "#00BFA5" : "#FA8072",\n        border:"3px solid #222",\n        borderRadius:16,\n        color: variant === "green" ? "#1A1A1A" : "white",\n        fontSize:17,\n        fontWeight:900,\n        padding:"14px 24px",\n        cursor:"pointer",\n        boxShadow:"5px 5px 0 #222",\n        textTransform:"uppercase",\n        letterSpacing:0.5\n      }}\n    >\n      {children}\n    </button>\n  );\n\n  const SpeechBubble = ({ who, children }) => (\n    <div style={{\n      background:"#FFF8F0",\n      border:"3px solid #222",\n      borderRadius: who === "max" ? "24px 24px 6px 24px" : "24px 24px 24px 6px",\n      padding:"18px 22px",\n      boxShadow:"6px 6px 0 rgba(0,0,0,0.22)",\n      maxWidth:520,\n      lineHeight:1.55,\n      fontSize:18,\n      fontWeight:800,\n      color:"#222"\n    }}>\n      <div style={{ fontSize:12, fontWeight:900, color: who === "max" ? "#D4622D" : "#558B2F", textTransform:"uppercase", letterSpacing:2, marginBottom:8 }}>\n        {who === "max" ? "Max — coach nutrition" : playerName || "Toi"}\n      </div>\n      {children}\n    </div>\n  );\n\n  return (\n    <div style={{ position:"fixed", inset:0, fontFamily:"Arial, sans-serif", overflow:"hidden", backgroundImage:"url(\'/fond_vert3.png\')", backgroundSize:"cover", backgroundPosition:"center" }}>\n      <div style={{ position:"absolute", inset:0, background:"linear-gradient(135deg, rgba(26,58,92,0.82), rgba(0,191,165,0.46))" }} />\n\n      <button onClick={onBack} style={{ position:"absolute", top:18, left:18, zIndex:20, background:"white", border:"3px solid #222", borderRadius:12, padding:"9px 16px", fontSize:14, fontWeight:900, cursor:"pointer", boxShadow:"3px 3px 0 #222" }}>\n        ← Retour\n      </button>\n\n      <div style={{ position:"absolute", top:18, right:24, zIndex:20, display:"flex", gap:8 }}>\n        {["Profil", "Recommandations", "Recettes"].map((label, i) => (\n          <div key={label} style={{ padding:"8px 14px", borderRadius:20, border:"2px solid #222", background: etape === i ? "#FFDD44" : "rgba(255,255,255,0.86)", fontSize:12, fontWeight:900, boxShadow: etape === i ? "3px 3px 0 #222" : "none" }}>\n            {i + 1}. {label}\n          </div>\n        ))}\n      </div>\n\n      <img src={avatarSrc} alt="Avatar" style={{ position:"absolute", left:"1%", bottom:-35, height:"62vh", maxWidth:"36vw", objectFit:"contain", filter:"drop-shadow(8px 10px 0 rgba(0,0,0,0.25))", zIndex:4 }} />\n      <img src="/e.png" alt="Max" style={{ position:"absolute", right:"2%", bottom:-40, height:"74vh", maxWidth:"38vw", objectFit:"contain", filter:"drop-shadow(8px 10px 0 rgba(0,0,0,0.28))", zIndex:4 }} />\n\n      <div style={{ position:"relative", zIndex:8, height:"100vh", padding:"78px 30px 28px", boxSizing:"border-box", display:"flex", flexDirection:"column", alignItems:"center" }}>\n        {etape === 0 && (\n          <>\n            <div style={{ textAlign:"center", color:"white", marginBottom:18 }}>\n              <div style={{ display:"inline-block", background:"#FFDD44", color:"#222", border:"3px solid #222", borderRadius:22, padding:"8px 18px", fontSize:14, fontWeight:900, boxShadow:"4px 4px 0 #222", marginBottom:12 }}>\n                MISSION QCM2 TERMINÉE\n              </div>\n              <h1 style={{ margin:0, fontSize:58, fontWeight:900, textShadow:"4px 4px 0 rgba(0,0,0,0.25)" }}>\n                Ton profil alimentaire est débloqué\n              </h1>\n            </div>\n\n            <div style={{ display:"grid", gridTemplateColumns:"1fr 1.1fr 1fr", gap:22, width:"100%", maxWidth:1120, alignItems:"center" }}>\n              <SpeechBubble who="player">\n                Max, j\'ai terminé le QCM2. Qu\'est-ce que mes réponses disent sur mon alimentation ?\n              </SpeechBubble>\n\n              <div style={{ background:"rgba(255,255,255,0.96)", border:"4px solid #222", borderRadius:28, padding:24, boxShadow:"10px 10px 0 rgba(0,0,0,0.28)" }}>\n                <div style={{ display:"flex", alignItems:"center", gap:14, marginBottom:18 }}>\n                  <div style={{ width:70, height:70, borderRadius:20, background:profilPrincipal.bg, border:`3px solid ${profilPrincipal.couleur}`, display:"flex", alignItems:"center", justifyContent:"center" }}>\n                    <img src={profilPrincipal.icon} alt="" style={{ width:50, height:50, objectFit:"contain" }} />\n                  </div>\n                  <div>\n                    <div style={{ fontSize:13, color:"#666", fontWeight:900, textTransform:"uppercase", letterSpacing:1.5 }}>Carte profil</div>\n                    <div style={{ fontSize:30, fontWeight:900, color:profilPrincipal.couleur }}>{profilPrincipal.label}</div>\n                  </div>\n                </div>\n\n                <div style={{ background:"#F8FAFC", border:"2px solid #E8EDF2", borderRadius:18, padding:16, marginBottom:16 }}>\n                  <div style={{ fontSize:13, fontWeight:900, color:"#6B7280", textTransform:"uppercase", marginBottom:8 }}>Indice mission</div>\n                  <div style={{ height:20, background:"#E8EDF2", borderRadius:20, overflow:"hidden", border:"2px solid #222" }}>\n                    <div style={{ width:`${missionScore}%`, height:"100%", background:"linear-gradient(90deg,#9ACD32,#00BFA5)", borderRight:"2px solid #222" }} />\n                  </div>\n                  <div style={{ marginTop:8, fontSize:14, fontWeight:900, color:"#1A3A5C" }}>{missionScore}% analysé · {badgeRepas}</div>\n                </div>\n\n                <p style={{ fontSize:17, lineHeight:1.65, color:"#333", fontWeight:700, margin:"0 0 16px" }}>{profilPrincipal.texte}</p>\n\n                <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>\n                  {profilRecos.map(p => (\n                    <span key={p.key} style={{ background:p.bg, color:p.couleur, border:`2px solid ${p.couleur}`, borderRadius:20, padding:"7px 12px", fontSize:12, fontWeight:900 }}>\n                      {p.label}\n                    </span>\n                  ))}\n                </div>\n              </div>\n\n              <SpeechBubble who="max">\n                Bien joué ! J\'ai analysé tes habitudes. Maintenant, je vais transformer ton profil en conseils concrets, puis en recettes personnalisées.\n              </SpeechBubble>\n            </div>\n\n            <div style={{ marginTop:24 }}>\n              <GameButton onClick={goNext} variant="green">Continuer la mission →</GameButton>\n            </div>\n          </>\n        )}\n\n        {etape === 1 && (\n          <>\n            <div style={{ textAlign:"center", color:"white", marginBottom:20 }}>\n              <div style={{ display:"inline-block", background:"#00BFA5", color:"white", border:"3px solid #222", borderRadius:22, padding:"8px 18px", fontSize:14, fontWeight:900, boxShadow:"4px 4px 0 #222", marginBottom:12 }}>\n                CONSEILS DÉBLOQUÉS\n              </div>\n              <h1 style={{ margin:0, fontSize:54, fontWeight:900, textShadow:"4px 4px 0 rgba(0,0,0,0.25)" }}>\n                Max te donne tes recommandations\n              </h1>\n            </div>\n\n            <div style={{ width:"100%", maxWidth:1080, display:"grid", gridTemplateColumns:"1fr 1fr", gap:18 }}>\n              {profilRecos.map((p, idx) => (\n                <div key={p.key} style={{ background:"white", border:"4px solid #222", borderRadius:24, padding:20, boxShadow:"8px 8px 0 rgba(0,0,0,0.25)", transform:idx%2 ? "rotate(1deg)" : "rotate(-1deg)" }}>\n                  <div style={{ display:"flex", alignItems:"center", gap:14, marginBottom:12 }}>\n                    <div style={{ width:58, height:58, borderRadius:18, background:p.bg, border:`3px solid ${p.couleur}`, display:"flex", alignItems:"center", justifyContent:"center" }}>\n                      <img src={p.icon} alt="" style={{ width:42, height:42, objectFit:"contain" }} />\n                    </div>\n                    <div style={{ fontSize:24, fontWeight:900, color:p.couleur }}>{p.label}</div>\n                  </div>\n                  <p style={{ margin:"0 0 12px", fontSize:15, lineHeight:1.55, color:"#444", fontWeight:700 }}>{p.texte}</p>\n                  <div style={{ display:"grid", gap:8 }}>\n                    {p.conseils.map((c, i) => (\n                      <div key={i} style={{ background:p.bg, border:`2px solid ${p.couleur}`, borderRadius:14, padding:"9px 12px", fontSize:14, fontWeight:800, color:"#222" }}>\n                        ✓ {c}\n                      </div>\n                    ))}\n                  </div>\n                </div>\n              ))}\n            </div>\n\n            <div style={{ position:"absolute", right:"22%", bottom:"18%", zIndex:12 }}>\n              <SpeechBubble who="max">\n                Clique ici pour transformer ces recommandations en recettes adaptées à ton profil.\n              </SpeechBubble>\n            </div>\n\n            <div style={{ marginTop:24, display:"flex", gap:14 }}>\n              <GameButton onClick={() => setEtape(0)} variant="blue">← Profil</GameButton>\n              <GameButton onClick={goNext} variant="green">Voir les recettes →</GameButton>\n            </div>\n          </>\n        )}\n\n        {etape === 2 && (\n          <>\n            <div style={{ textAlign:"center", color:"white", marginBottom:22 }}>\n              <div style={{ display:"inline-block", background:"#FA8072", color:"white", border:"3px solid #222", borderRadius:22, padding:"8px 18px", fontSize:14, fontWeight:900, boxShadow:"4px 4px 0 #222", marginBottom:12 }}>\n                RECETTES PERSONNALISÉES\n              </div>\n              <h1 style={{ margin:0, fontSize:54, fontWeight:900, textShadow:"4px 4px 0 rgba(0,0,0,0.25)" }}>\n                La Fabrique à Menus est prête\n              </h1>\n            </div>\n\n            <div style={{ width:"100%", maxWidth:980, background:"rgba(255,255,255,0.96)", border:"4px solid #222", borderRadius:30, padding:26, boxShadow:"10px 10px 0 rgba(0,0,0,0.28)", display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:16 }}>\n              {[\n                { img:"/salade_grecque.png", title:"Menu frais", txt:"Une assiette simple, colorée et riche en légumes." },\n                { img:"/curry_lentille.png", title:"Menu malin", txt:"Des protéines végétales et des féculents pour tenir la journée." },\n                { img:"/poisson_oseille.png", title:"Menu équilibre", txt:"Une alternative légère avec poisson, légumes et goût." }\n              ].map((r) => (\n                <div key={r.title} style={{ background:"#F8FAFC", border:"3px solid #222", borderRadius:22, padding:12, textAlign:"center", boxShadow:"5px 5px 0 rgba(0,0,0,0.18)" }}>\n                  <img src={r.img} alt="" style={{ width:"100%", height:120, objectFit:"contain", marginBottom:8 }} />\n                  <div style={{ fontSize:18, fontWeight:900, color:"#1A3A5C" }}>{r.title}</div>\n                  <div style={{ fontSize:13, color:"#555", fontWeight:700, lineHeight:1.45 }}>{r.txt}</div>\n                </div>\n              ))}\n            </div>\n\n            <div style={{ marginTop:24, display:"flex", gap:14 }}>\n              <GameButton onClick={() => setEtape(1)} variant="blue">← Recommandations</GameButton>\n              <GameButton onClick={() => onVoirRecettes(profilPrincipal.profil)} variant="green">Débloquer mes recettes →</GameButton>\n            </div>\n          </>\n        )}\n      </div>\n    </div>\n  );\n}\n\n'

text = text[:start] + new_component + text[end:]

old_call = 'if (phase === "recos_qcm2") return <RecommandationsQcm2Screen answers={qcm2Answers} onBack={() => goBack()} onVoirRecettes={(profil) => { setFiltreRecetteProfil(profil); goTo("recettes"); }} />;'
new_call = 'if (phase === "recos_qcm2") return <RecommandationsQcm2Screen answers={qcm2Answers} playerName={playerName} avatarChoice={avatarChoice} onBack={() => goBack()} onVoirRecettes={(profil) => { setFiltreRecetteProfil(profil); goTo("recettes"); }} />;'

if old_call in text:
    text = text.replace(old_call, new_call)
elif "if (phase === \"recos_qcm2\") return <RecommandationsQcm2Screen" in text and "avatarChoice={avatarChoice}" not in text:
    print("⚠️ Le composant a été remplacé, mais l'appel recos_qcm2 n'a pas été modifié automatiquement.")
    print("➡️ Si ton avatar n'apparaît pas, envoie-moi la ligne recos_qcm2.")
else:
    print("ℹ️ L'appel recos_qcm2 semble déjà modifié ou a une forme différente.")

TARGET.write_text(text, encoding="utf-8")

print("✅ Patch QCM2 v2 appliqué !")
print(f"💾 Sauvegarde créée : {backup.name}")
print("➡️ Retourne à la racine du projet puis lance : npm run dev")
